import { publicRequest, userRequest } from "../requestMethods";
import { getNotificationFailure, getNotificationStart, getNotificationSuccess, notificationReadFailure, notificationReadStart, notificationReadSuccess } from "./notificationRedux";
import { 
    getOrderStart, 
    getOrderSuccess,
    getOrderFailure,
    deleteOrderStart,
    deleteOrderSuccess,
    deleteOrderFailure,
    updateOrderStart,
    updateOrderSuccess,
    updateOrderFailure, 
} from "./orderRedux";
import { 
    addProductFailure,
    addProductStart,
    addProductSuccess,
    deleteProductFailure, 
    deleteProductStart, 
    deleteProductSuccess, 
    getProductFailure, 
    getProductStart, 
    getProductSuccess, 
    updateProductFailure, 
    updateProductStart,
    updateProductSuccess,
} from "./productRedux";
import { 
    loginFailure, 
    loginStart, 
    loginSuccess,
    logoutStart, 
    logoutSuccess, 
    logoutFailure, 
    getUsersStart,
    getUsersSuccess,
    getUsersFailure,
    deleteUserStart,
    deleteUserSuccess,
    deleteUserFailure,
    refreshTokenStart,
    refreshTokenSuccess,
    refreshTokenFailure,
    updateUserSuccess,
    updateUserStart,
    updateUserFailure
 } from "./userRedux";
import { useNavigate } from "react-router-dom";


 const navigate = useNavigate();

export const refreshAccessToken = async (dispatch, refreshToken, refreshTokenId) => {

    dispatch(refreshTokenStart());
    try {
        const res = await publicRequest.put("/auth/refresh_token", {refreshToken, refreshTokenId}, {
            withCredentials: true
        });
        dispatch(refreshTokenSuccess(res.data));
        return res.data;
    } catch(err) {
        dispatch(refreshTokenFailure());
    }
}

export const login = async (dispatch, user) => {
    dispatch(loginStart());
    try {
        const res = await publicRequest.post("/auth/login", user)
        dispatch(loginSuccess(res.data))
        navigate("/");
    } catch(err) {
        dispatch(loginFailure());
    }
};

export const logout = async (dispatch, user) => {
    dispatch(logoutStart());
    try {
        const res = await userRequest.post("/auth/logout_post", user)
        dispatch(logoutSuccess(res));
    } catch(err) {
        dispatch(logoutFailure());
        console.log(err)
    }
};

export const getProducts = async (dispatch) => {
    dispatch(getProductStart());
    try {
        const res = await publicRequest.get("/products");
        dispatch(getProductSuccess(res.data))
    } catch(err) {
        dispatch(getProductFailure());
    }
};

export const deleteProduct = async (id, dispatch) => {
    dispatch(deleteProductStart());
    try {
        await userRequest.delete(`/products/${id}`)
        dispatch(deleteProductSuccess(id))
    } catch(err) {
        dispatch(deleteProductFailure());
    }
};

export const updateProduct = async (id, product, dispatch) => {
    dispatch(updateProductStart());
    try {
        // update 
        await userRequest.put(`/products/${id}`, product);
        dispatch(updateProductSuccess({id, product}))
    } catch(err) {
        dispatch(updateProductFailure());
    }
};

export const addProduct = async (product, dispatch) => {
    dispatch(addProductStart());
    try {
        const res = await userRequest.post(`/products`, product);
        dispatch(addProductSuccess(res.data));
    } catch(err) {
        dispatch(addProductFailure());
    }
};

export const getUsers = async (dispatch) => {
    dispatch(getUsersStart());
    try {
        const res = await userRequest.get('/users');
        dispatch(getUsersSuccess(res.data));
    } catch(err) {
        dispatch(getUsersFailure());
    }
};

export const deleteUser = async (id, dispatch) => {
    dispatch(deleteUserStart());
    try {
        await userRequest.delete(`/users/${id}`)
        dispatch(deleteUserSuccess(id))
    } catch(err) {
        dispatch(deleteUserFailure());
    }
};

export const updateUser = async (id, user, dispatch) => {
    dispatch(updateUserStart());
    try {
        const res = await userRequest.put(`/users/${id}`, user);
        const updatedUser = res.data;
        dispatch(updateUserSuccess({id, updatedUser}));
    } catch(err) {
        dispatch(updateUserFailure());
        console.log(err)
    }
};

export const getOrders = async (dispatch) => {
    dispatch(getOrderStart());
    try {
        const res = await userRequest.get("/orders");
        dispatch(getOrderSuccess(res.data))
    } catch(err) {
        dispatch(getOrderFailure());
    }
};

export const deleteOrder = async (id, dispatch) => {
    dispatch(deleteOrderStart());
    try {
        await userRequest.delete(`/orders/${id}`)
        dispatch(deleteOrderSuccess(id))
    } catch(err) {
        dispatch(deleteOrderFailure());
    }
};

export const updateOrder = async (id, order, dispatch) => {
    dispatch(updateOrderStart());
    try {
        // update 
        const res = await userRequest.put(`/orders/${id}`, order);
        const updatedOrder = res.data;
        dispatch(updateOrderSuccess({id, updatedOrder}))
    } catch(err) {
        dispatch(updateOrderFailure());
        console.log(err)
    }
};

export const getNotifications = async (dispatch) => {
    dispatch(getNotificationStart());
    try {
        const res = await userRequest.get("/notifications");
        dispatch(getNotificationSuccess(res.data))
    } catch(err) {
        dispatch(getNotificationFailure());
        console.log(err);
    }
}

export const updatedNotification = async (id, notification, dispatch) => {
    console.log("id => ", id)
    console.log("notification => ", notification)
    dispatch(notificationReadStart());
    try {
        await userRequest.put(`/notifications/${id}`, notification);
        dispatch(notificationReadSuccess(id))
    } catch(err) {
        dispatch(notificationReadFailure());
        console.log(err)
    }
}
